import Footer from "../../Components/Footer/Footer";
import Navbar from "../../Components/Navbar/navbar";
import "./AboutUs.css";
import Aos from "aos";
import "aos/dist/aos.css";

function AboutUs() {
  useEffect(() => {
    Aos.init({ duration: 2000 });
  }, []);
  return (
    <>
      <Navbar />
      <section className="about-us">
        <h1>About Us</h1>
        <hr class="solid"></hr>

        <h2>Our Founding Story</h2>
        <p>
          At Sweet Treats, our journey began in a cozy kitchen, where our
          founder, Emily, experimented with delightful biscuit and chocolate
          recipes. Inspired by her grandmother’s secret cocoa blend, she decided
          to share these delectable creations with the world.
        </p>
        <h2>Meet Our Team</h2>
        <h3>Emily Johnson - Founder & Chief Chocolatier</h3>
        <p>
          Emily’s passion for sweets led her to create unique flavor
          combinations that dance on your taste buds. With a background in
          culinary arts, she ensures every bite is a moment of bliss.
        </p>
        <h3>Alex Rodriguez - Head Baker</h3>
        <p>
          Alex’s love for biscuits started at an early age. His dedication to
          perfection ensures that each biscuit is flaky, buttery, and
          irresistible.
        </p>
        <h2>Our Evolution</h2>
        <p>
          From humble beginnings at local farmers’ markets to our bustling
          storefront, we’ve grown alongside our loyal customers. We’ve expanded
          our product line, introduced vegan options, and even won awards for
          our dark chocolate truffles. Join us on this sweet adventure, and let
          our treats brighten your day!
        </p>
      </section>
      <Footer />
    </>
  );
}

export default AboutUs;
